#include <bits/stdc++.h>

using namespace std;

const long long mod = 1e9 + 7;
const long long inf = 1e18;
const int MAX_SIZE = 1e6 + 1;

// Function to initialize isPrime and smallestPrimeFactor arrays
void sieve(vector < bool > & isPrime, vector < int > & smallestPrimeFactor) {
    isPrime[0] = isPrime[1] = false; // 0 and 1 are not prime
    for (int i = 2; i < MAX_SIZE; i++) {
        if (isPrime[i]) {
            smallestPrimeFactor[i] = i; // Initialize smallest prime factor
            for (int j = i * 2; j < MAX_SIZE; j += i) {
                isPrime[j] = false; // Mark multiples of i as non-prime
                if (smallestPrimeFactor[j] == 0) {
                    smallestPrimeFactor[j] = i; // Update smallest prime factor
                }
            }
        }
    }
}

int main() {
    vector < bool > isPrime(MAX_SIZE, true);
    vector < int > smallestPrimeFactor(MAX_SIZE, 0);
    sieve(isPrime, smallestPrimeFactor); // Precompute primes

    int t;
    cin >> t; // Read number of test cases

    while (t--) {
        int n;
        cin >> n; // Read size of the array
        map < int, int > cnt; // Map to count occurrences of prime factors

        for (int i = 0; i < n; i++) {
            int x;
            cin >> x; // Read each number
            while (x > 1) {
                cnt[smallestPrimeFactor[x]]++; // Count the prime factor
                x /= smallestPrimeFactor[x]; // Divide x by its smallest prime factor
            }
        }

        long long ans = 1; // Initialize answer
        for (const auto & it: cnt) {
            ans *= (it.second + 1); // Calculate the product of (count + 1)
        }
        cout << ans << '\n'; // Output the result for the current test case
    }
    return 0;
}

