const readline = require('readline');

const MAX_SIZE = 1e6 + 1;

// Sieve of Eratosthenes to find smallest prime factors
function sieve() {
    const isPrime = new Array(MAX_SIZE).fill(true);
    const smallestPrimeFactor = new Array(MAX_SIZE).fill(0);
    isPrime[0] = isPrime[1] = false; // 0 and 1 are not prime

    for (let i = 2; i < MAX_SIZE; i++) {
        if (isPrime[i]) {
            smallestPrimeFactor[i] = i; // Initialize smallest prime factor
            for (let j = i * 2; j < MAX_SIZE; j += i) {
                isPrime[j] = false; // Mark multiples of i as non-prime
                if (smallestPrimeFactor[j] === 0) {
                    smallestPrimeFactor[j] = i; // Update smallest prime factor
                }
            }
        }
    }
    return smallestPrimeFactor;
}

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

const smallestPrimeFactor = sieve(); // Precompute smallest prime factors

let inputBuffer = '';

// Collecting all input data
rl.on('line', (line) => {
    inputBuffer += line + '\n';
});

rl.on('close', () => {
    const inputLines = inputBuffer.trim().split('\n');
    const t = Number(inputLines[0]); // Number of test cases
    let output = '';

    let index = 1;
    for (let i = 0; i < t; i++) {
        const n = Number(inputLines[index++]); // Size of the array
        const cnt = new Map(); // Map to count occurrences of prime factors

        const array = inputLines[index++].split(' ').map(Number); // Next N numbers

        array.forEach((x) => {
            while (x > 1) {
                const spf = smallestPrimeFactor[x];
                cnt.set(spf, (cnt.get(spf) || 0) + 1); // Count the prime factor
                x /= spf; // Divide x by its smallest prime factor
            }
        });

        let ans = 1; // Initialize answer
        for (const count of cnt.values()) {
            ans *= (count + 1); // Calculate the product of (count + 1)
        }
        output += ans + '\n'; // Store the result for the current test case
    }
    console.log(output.trim()); // Output all results at once
});
